const sharp = require\('sharp'\);
const path = require\('path'\);
const fs = require\('fs'\);

// Create thumbs directory
const thumbDir = path.join\('public', 'images', 'thumbs'\);
fs.mkdirSync\(thumbDir, { recursive: true }\);

async function createThumb\(src, name, width, height\) {
  const input = path.join\('public', 'images', src\);
  const output = path.join\(thumbDir, name\);
  if \(!fs.existsSync\(input\)\) { console.log\('SKIP: ' + input\); return; }
  const info = await sharp\(input\).resize\(width, height, { fit: 'cover' }\).webp\({ quality: 75 }\).toFile\(output\);
  const origSize = fs.statSync\(input\).size;
  console.log\(name + ': ' + \(origSize/1024\).toFixed\(0\) + 'KB -> ' + \(info.size/1024\).toFixed\(0\) + 'KB'\);
}

